final:
module top_module(obf_Clock,D,Qa,Qb,Qc);input obf_Clock;
    input D;
    output reg Qa,Qb,Qc;

    always @ (obf_Clock or D)
    if(obf_Clock)
    begin
        Qa <= D;
    end

    always @ (posedge obf_Clock)
    begin
        Qb <= D;
    end

    always @ (negedge obf_Clock)
    begin
        Qc <= D;
    end
endmodule
